var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"하늘이……?","JPN":"空が……？","ENG":"The sky...?","TWN":"天空……？"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"관리국 본부와의 연락이 끊어졌습니다.","JPN":"管理局本部との通信が切れました。","ENG":"We've lost contact with Administration HQ.","TWN":"管理局本部的聯繫中斷了。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"CSE 레벨 측정 결과… 4를 넘어가기 시작했어요.","JPN":"CSEレベルの測定結果……4を超え始めています。","ENG":"The CSE level readings... they're starting to exceed Level 4.","TWN":"CSE等級測量結果……開始突破4了。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"대균열로부터 거리가 떨어진 이 섬에도 여파가……!","JPN":"大亀裂から遠く離れたこの島にも余波が……！","ENG":"Even this island, far from the Grand Dimension Crevice, is feeling the impact...!","TWN":"連這座距離大峽谷這麼遠的島也受到影響……！"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"쳇, 벌써 여기까지…….","JPN":"チッ、もうここまで……","ENG":"Tch, it's already reached here...?","TWN":"嘖，已經蔓延到這裡了嗎……"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"잠깐, 저건……?","JPN":"待って、あれは……？","ENG":"Wait, what is that...?","TWN":"等等，那是……？"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"크, 크라켄의 촉수에요!","JPN":"ク、クラーケンの触手です！","ENG":"I-it's a Kraken tentacle!","TWN":"那、那是克拉肯的觸手！"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"기어코 여기까지 영역을 넓힌 건가……?","JPN":"ついにここまで縄張りを広げたの……？","ENG":"Has it actually expanded its territory this far...?","TWN":"它竟然把勢力範圍擴張到這裡了……？"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"모에나 씨. 대피를 준비하셔야 해요.","JPN":"モエナさん。急いで避難しなければなりません。","ENG":"Moena, you need to prepare for evacuation.","TWN":"莫埃娜，你必須準備避難了。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"저희 쪽에서 반드시 피난선을 준비하도록 하겠습니다.","JPN":"避難船はこちらで必ず用意します。","ENG":"We'll secure evacuation ships on our end.","TWN":"我們會立刻準備撤離船隻。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"모에나 씨는 섬 주민분들을 모두 모아주세요!","JPN":"モエナさんは島の住民たちを集めてください！","ENG":"Please gather all the islanders, Moena!","TWN":"請你先集合所有島上的居民！"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"저희는…….","JPN":"私たちは……","ENG":"We...","TWN":"我們……"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"에이버리 해적단이 구한 여러분들을 이렇게 내버려둘 수는 없어요.","JPN":"エイバリー海賊団が救った皆さんを、このまま放っておくわけにはいきません。","ENG":"We can't abandon the people saved by the Avery Pirates.","TWN":"艾維利海盜團救了你們，我們不可能就這樣丟下你們不管。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"저희, 관리국이 섬을 책임지겠습니다!","JPN":"私たち、管理局が島を守ります！","ENG":"We of the Administration will take responsibility for the island!","TWN":"我們管理局會負責這座島！"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그러니……!","JPN":"ですから……！","ENG":"So please...!","TWN":"所以……！"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"……알겠어요.","JPN":"……わかりました。","ENG":"...All right.","TWN":"……我明白了。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"엄니…….","JPN":"母ちゃん……","ENG":"Mama...","TWN":"媽媽……"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"우리 모네. 싸우는 걸 보니 많이 컸다고 느꼈어.","JPN":"モネ。戦ってる姿を見て、成長したなあと思ったわ。","ENG":"My Moene. Watching you fight... I can see just how much you've grown.","TWN":"我家莫妮，看你戰鬥的樣子，覺得你真的長大了很多。"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"모네는 모네가 할 수 있는 일을 하고 있겠니?","JPN":"モネはモネにできることをやってちょうだい。","ENG":"Moene, you'll do everything you can, won't you?","TWN":"莫妮，你有在做你能做到的事嗎？"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"엄마는 엄마가 해야 할 일을 할게.","JPN":"お母さんは、お母さんがやるべきことをする。","ENG":"Then... I'll do everything I can as well.","TWN":"媽媽也會去做媽媽該做的事。"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"섬사람들을 모으는 거야.","JPN":"島の人たちを集めるわ。","ENG":"I'll gather everyone on the island.","TWN":"我要去集合島上的人。"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"엄마가 그러는 동안… 모네는 잘 버텨줄 수 있지?","JPN":"お母さんがそうしてる間に……モネもしっかり踏ん張れるわね？","ENG":"While I'm doing that... can you hold out for us?","TWN":"在媽媽這麼做的期間……莫妮能撐得住吧？"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"모네 이제 다 컸슴다.","JPN":"モネ、もう大きくなったっす。","ENG":"Moene's all grown up now.","TWN":"莫妮現在已經長大了。"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"그 정도 부탁은 당연히 들어드릴 수 있슴다!","JPN":"それくらいの頼み、もちろん聞けるっす！","ENG":"I can handle a request like that, of course!","TWN":"這種請求當然能做到！"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"후후, 우리 모네, 착하네.","JPN":"ふふ、モネ、いい子ね。","ENG":"Fufu... my Moene. You're such a dependable girl.","TWN":"呵呵，我家莫妮真乖。"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"엄니도 힘내시지 말임다!","JPN":"母ちゃんも頑張るっす！","ENG":"Mama, you too! Hang in there!","TWN":"媽媽也會加油的！"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"모네, 믿음직한 분에게 지원도 요청했슴다!","JPN":"モネ、頼もしい人に支援も要請したっす！","ENG":"Moene already asked someone reliable for help!","TWN":"莫妮，我還請了一個可靠的人來支援！"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};